import Decimal from 'decimal.js-light';
import { curry } from './utils';
/**
 * ĶÄĘÕÅ¢µĢ░ÕĆ╝ńÜäõĮŹµĢ░
 * ÕģČõĖŁń╗ØÕ»╣ÕĆ╝Õ▒×õ║ÄÕī║ķŚ┤[0.1, 1)’╝ī ÕŠŚÕł░ńÜäÕĆ╝õĖ║0
 * ń╗ØÕ»╣ÕĆ╝Õ▒×õ║ÄÕī║ķŚ┤[0.01, 0.1)’╝īÕŠŚÕł░ńÜäõĮŹµĢ░õĖ║ -1
 * ń╗ØÕ»╣ÕĆ╝Õ▒×õ║ÄÕī║ķŚ┤[0.001, 0.01)’╝īÕŠŚÕł░ńÜäõĮŹµĢ░õĖ║ -2
 *
 * @param  {Number} value µĢ░ÕĆ╝
 * @return {Integer} õĮŹµĢ░
 */

function getDigitCount(value) {
  var result;

  if (value === 0) {
    result = 1;
  } else {
    result = Math.floor(new Decimal(value).abs().log(10).toNumber()) + 1;
  }

  return result;
}
/**
 * µīēńģ¦Õø║Õ«ÜńÜäµŁźķĢ┐ĶÄĘÕÅ¢[start, end)Ķ┐ÖõĖ¬Õī║ķŚ┤ńÜäµĢ░µŹ«
 * Õ╣ČõĖöķ£ĆĶ”üÕżäńÉåjsĶ«Īń«Śń▓ŠÕ║”ńÜäķŚ«ķóś
 *
 * @param  {Decimal} start ĶĄĘńé╣
 * @param  {Decimal} end   ń╗łńé╣’╝īõĖŹÕīģÕÉ½Ķ»źÕĆ╝
 * @param  {Decimal} step  µŁźķĢ┐
 * @return {Array}         ĶŗźÕ╣▓µĢ░ÕĆ╝
 */


function rangeStep(start, end, step) {
  var num = new Decimal(start);
  var i = 0;
  var result = []; // magic number to prevent infinite loop

  while (num.lt(end) && i < 100000) {
    result.push(num.toNumber());
    num = num.add(step);
    i++;
  }

  return result;
}
/**
 * Õ»╣µĢ░ÕĆ╝Ķ┐øĶĪīń║┐µĆ¦µÅÆÕĆ╝
 *
 * @param  {Number} a  Õ«Üõ╣ēÕ¤¤ńÜäµ×üńé╣
 * @param  {Number} b  Õ«Üõ╣ēÕ¤¤ńÜäµ×üńé╣
 * @param  {Number} t  [0, 1]ÕåģńÜäµ¤ÉõĖ¬ÕĆ╝
 * @return {Number}    Õ«Üõ╣ēÕ¤¤ÕåģńÜäµ¤ÉõĖ¬ÕĆ╝
 */


var interpolateNumber = curry(function (a, b, t) {
  var newA = +a;
  var newB = +b;
  return newA + t * (newB - newA);
});
/**
 * ń║┐µĆ¦µÅÆÕĆ╝ńÜäķĆåĶ┐Éń«Ś
 *
 * @param  {Number} a Õ«Üõ╣ēÕ¤¤ńÜäµ×üńé╣
 * @param  {Number} b Õ«Üõ╣ēÕ¤¤ńÜäµ×üńé╣
 * @param  {Number} x ÕÅ»õ╗źĶ«żõĖ║µś»µÅÆÕĆ╝ÕÉÄńÜäõĖĆõĖ¬ĶŠōÕć║ÕĆ╝
 * @return {Number}   ÕĮōxÕ£© a ~ bĶ┐ÖõĖ¬ĶīāÕø┤ÕåģµŚČ’╝īĶ┐öÕø×ÕĆ╝Õ▒×õ║Ä[0, 1]
 */

var uninterpolateNumber = curry(function (a, b, x) {
  var diff = b - +a;
  diff = diff || Infinity;
  return (x - a) / diff;
});
/**
 * ń║┐µĆ¦µÅÆÕĆ╝ńÜäķĆåĶ┐Éń«Ś’╝īÕ╣ČõĖöµ£ēµł¬µ¢ŁńÜäµōŹõĮ£
 *
 * @param  {Number} a Õ«Üõ╣ēÕ¤¤ńÜäµ×üńé╣
 * @param  {Number} b Õ«Üõ╣ēÕ¤¤ńÜäµ×üńé╣
 * @param  {Number} x ÕÅ»õ╗źĶ«żõĖ║µś»µÅÆÕĆ╝ÕÉÄńÜäõĖĆõĖ¬ĶŠōÕć║ÕĆ╝
 * @return {Number}   ÕĮōxÕ£© a ~ bĶ┐ÖõĖ¬Õī║ķŚ┤ÕåģµŚČ’╝īĶ┐öÕø×ÕĆ╝Õ▒×õ║Ä[0, 1]’╝ī
 * ÕĮōxõĖŹÕ£© a ~ bĶ┐ÖõĖ¬Õī║ķŚ┤µŚČ’╝īõ╝Üµł¬µ¢ŁÕł░ a ~ b Ķ┐ÖõĖ¬Õī║ķŚ┤
 */

var uninterpolateTruncation = curry(function (a, b, x) {
  var diff = b - +a;
  diff = diff || Infinity;
  return Math.max(0, Math.min(1, (x - a) / diff));
});
export default {
  rangeStep: rangeStep,
  getDigitCount: getDigitCount,
  interpolateNumber: interpolateNumber,
  uninterpolateNumber: uninterpolateNumber,
  uninterpolateTruncation: uninterpolateTruncation
};